create unique index if not exists music_likes_track_user_unique on public.music_likes(track_id,user_id);
create unique index if not exists podcast_likes_episode_user_unique on public.podcast_likes(episode_id,user_id);
create unique index if not exists radio_likes_station_user_unique on public.radio_likes(station_id,user_id);
create unique index if not exists playlist_tracks_playlist_track_unique on public.playlist_tracks(playlist_id,track_id);
create index if not exists music_tracks_public_created_idx on public.music_tracks(is_published,visibility,created_at desc);
create index if not exists podcast_episodes_public_created_idx on public.podcast_episodes(is_published,visibility,created_at desc);
create index if not exists radio_stations_public_created_idx on public.radio_stations(is_public,created_at desc);
create index if not exists music_comments_track_created_idx on public.music_comments(track_id,created_at desc);
create index if not exists podcast_comments_episode_created_idx on public.podcast_comments(episode_id,created_at desc);
create index if not exists audio_history_user_played_idx on public.audio_listening_history(user_id,last_played_at desc);
